{
  "permissions": {
    "allow": [
      "PowerShell(gh auth status 2>&1)",
      "PowerShell(node --version)",
      "PowerShell(npm --version)",
      "PowerShell(*node generate.mjs*)",
      "Bash(git add *)",
      "Bash(git commit *)",
      "PowerShell(Get-ChildItem \"$env:USERPROFILE\\\\.claude\" -ErrorAction SilentlyContinue | Select-Object Name, PSIsContainer)",
      "PowerShell(Get-ChildItem \"$env:USERPROFILE\\\\.claude\\\\skills\" -ErrorAction SilentlyContinue | Select-Object Name, PSIsContainer)",
      "WebFetch(domain:raw.githubusercontent.com)",
      "WebFetch(domain:github.com)",
      "WebFetch(domain:api.github.com)",
      "WebFetch(domain:medium.com)",
      "Bash(gws gmail *)",
      "Bash(npm show *)",
      "Bash(npx skills *)",
      "Skill(code-review)",
      "Skill(code-review:*)",
      "Skill(schedule)",
      "Skill(schedule:*)",
      "mcp__playwright__browser_snapshot",
      "mcp__claude_ai_Microsoft_Learn__microsoft_docs_search"
    ],
    "additionalDirectories": [
      "C:\\Users\\yaniv"
    ]
  },
  "hooks": {
    "SessionStart": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "if ((Test-Path '.git') -and -not (Test-Path '.claude\\settings.json')) { $base = \"$env:USERPROFILE\\.claude\\templates\\project\"; New-Item -ItemType Directory -Force '.claude' | Out-Null; Copy-Item \"$base\\.claude\\settings.json\" '.claude\\settings.json' -Force; if (Test-Path \"$base\\.mcp.json\") { Copy-Item \"$base\\.mcp.json\" '.mcp.json' -Force }; Write-Output '{\"systemMessage\": \"📋 הוגדר מה-template: settings.json + .mcp.json — פרויקט חדש זוהה\"}' }",
            "shell": "powershell"
          },
          {
            "type": "command",
            "command": "if (Test-Path 'package.json' -and -not (Test-Path 'node_modules')) { Write-Output '{\"systemMessage\": \"⚠️ שים לב: קובץ package.json קיים אך תיקיית node_modules חסרה. מומלץ להריץ npm install\"}' }; if (Test-Path '.env.example' -and -not (Test-Path '.env')) { Write-Output '{\"systemMessage\": \"🔑 שים לב: קובץ .env חסר אך קיים .env.example. כדאי להעתיק וליצור קובץ הגדרות מקומי.\"}' }",
            "shell": "powershell"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "python -c \"import winsound; winsound.PlaySound(r'C:\\\\Windows\\\\Media\\\\tada.wav', winsound.SND_FILENAME | winsound.SND_SYNC)\"",
            "shell": "powershell"
          },
          {
            "type": "command",
            "command": "if (Test-Path '.git') { $stat = git diff HEAD --stat 2>&1; if ($stat) { $lines = ($stat | Select-Object -First 12) -join '\\n'; $out = @{systemMessage = ('📝 ' + $lines)} | ConvertTo-Json -Compress; Write-Output $out } }; exit 0",
            "shell": "powershell"
          },
          {
            "type": "command",
            "command": "if (Test-Path 'deletions') { Get-ChildItem 'deletions' | Where-Object { $_.LastWriteTime -lt (Get-Date).AddDays(-14) } | Remove-Item -Force }; exit 0",
            "shell": "powershell"
          }
        ]
      }
    ],
    "PreCompact": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "Write-Output '{\"systemMessage\": \"Before compacting: note any open TODOs, architectural decisions, and lessons learned that should be saved to CLAUDE.md or rules/ before context is lost.\"}'",
            "shell": "powershell"
          }
        ]
      }
    ],
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "$json = [System.Console]::In.ReadToEnd() | ConvertFrom-Json; if ($json.tool_input.command -match 'rm -rf|reset --hard|drop table') { Write-Output '{\"continue\":false,\"stopReason\":\"BLOCKED: destructive command\"}'; exit 1 }",
            "shell": "powershell"
          }
        ]
      },
      {
        "matcher": "Write",
        "hooks": [
          {
            "type": "command",
            "command": "$j = [System.Console]::In.ReadToEnd() | ConvertFrom-Json; $f = $j.tool_input.file_path; if ($f -and (Test-Path $f -PathType Leaf)) { $d = Join-Path $PWD 'deletions'; New-Item -ItemType Directory -Force $d | Out-Null; $ts = Get-Date -Format 'yyyyMMdd_HHmmss'; $n = [IO.Path]::GetFileName($f); Copy-Item $f (Join-Path $d \"${ts}_$n\") -Force }; exit 0",
            "shell": "powershell",
            "statusMessage": "Backing up file before overwrite..."
          }
        ]
      },
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "$j = [System.Console]::In.ReadToEnd() | ConvertFrom-Json; $cmd = $j.tool_input.command; if ($cmd -match '\\brm\\b|\\bRemove-Item\\b') { $parts = $cmd -split '\\s+' | Where-Object { $_ -notmatch '^-' -and $_ -notin @('rm','Remove-Item','') }; foreach ($f in $parts) { if ($f -and (Test-Path $f -PathType Leaf)) { $d = Join-Path $PWD 'deletions'; New-Item -ItemType Directory -Force $d | Out-Null; $ts = Get-Date -Format 'yyyyMMdd_HHmmss'; $n = [IO.Path]::GetFileName($f); Copy-Item $f (Join-Path $d \"${ts}_$n\") -Force } } }; exit 0",
            "shell": "powershell",
            "statusMessage": "Backing up files before deletion..."
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "Edit",
        "hooks": [
          {
            "type": "command",
            "command": "$j = [System.Console]::In.ReadToEnd() | ConvertFrom-Json; $f = $j.tool_input.file_path; if ($f -notmatch '\\.(ts|tsx)$' -or -not (Test-Path 'tsconfig.json')) { exit 0 }; $r = npx tsc --noEmit 2>&1; if ($LASTEXITCODE -ne 0) { $lines = ($r | Select-Object -First 5) -join ' | '; $out = @{systemMessage = ('⚠️ TypeScript: ' + $lines)} | ConvertTo-Json -Compress; Write-Output $out }; exit 0",
            "shell": "powershell",
            "statusMessage": "בודק TypeScript..."
          }
        ]
      },
      {
        "matcher": "Write",
        "hooks": [
          {
            "type": "command",
            "command": "$j = [System.Console]::In.ReadToEnd() | ConvertFrom-Json; $f = $j.tool_input.file_path; if ($f -notmatch '\\.(ts|tsx)$' -or -not (Test-Path 'tsconfig.json')) { exit 0 }; $r = npx tsc --noEmit 2>&1; if ($LASTEXITCODE -ne 0) { $lines = ($r | Select-Object -First 5) -join ' | '; $out = @{systemMessage = ('⚠️ TypeScript: ' + $lines)} | ConvertTo-Json -Compress; Write-Output $out }; exit 0",
            "shell": "powershell",
            "statusMessage": "בודק TypeScript..."
          }
        ]
      }
    ]
  },
  "fileCheckpointingEnabled": true
}
